// const ratingColor = r => ["","#ef4444","#f97316","#eab308","#84cc16","#22c55e","#10b981"][r];
// const phaseIcon = { "Initial Ratings": "📊", "Open Discussion": "💬", "Final Ratings": "✅" };
const ratingColor = (r: number) => ["","#ef4444","#f97316","#eab308","#84cc16","#22c55e","#10b981"][r];
const phaseIcon: Record<string, string> = { "Initial Ratings": "📊", "Open Discussion": "💬", "Final Ratings": "✅" };

export default function App() {
  const [si, setSi] = useState(0);
  const [pi, setPi] = useState(0);
  // const [expanded, setExpanded] = useState({});
  const [expanded, setExpanded] = useState<Record<string, boolean>>({});


  const sc = scenarios[si];
  const ph = sc.discussions[pi];

  // const toggle = key => setExpanded(e => ({ ...e, [key]: !e[key] }));
  const toggle = (key: string) => setExpanded(e => ({ ...e, [key]: !e[key] }));

  return (
    <div style={{ fontFamily: "'Segoe UI', sans-serif", background: "#0f172a", minHeight: "100vh", color: "#e2e8f0", display: "flex", flexDirection: "column", height: "100vh" }}>
      {/* Header */}
      <div style={{ background: "#1e293b", borderBottom: "1px solid #334155", padding: "12px 20px", flexShrink: 0 }}>
        <div style={{ fontSize: 11, color: "#64748b", marginBottom: 2, textTransform: "uppercase", letterSpacing: 1 }}>Moral Reasoning Study — Group Discussion Simulation</div>
        <div style={{ fontSize: 16, fontWeight: 700, color: "#f1f5f9" }}>Deliberative Ethics: AI-Mediated Moral Judgment</div>
      </div>

      <div style={{ display: "flex", flex: 1, overflow: "hidden" }}>
        {/* Sidebar */}
        <div style={{ width: 210, background: "#1e293b", borderRight: "1px solid #334155", overflowY: "auto", flexShrink: 0 }}>
          <div style={{ fontSize: 10, fontWeight: 700, color: "#475569", padding: "10px 12px 6px", textTransform: "uppercase", letterSpacing: 1 }}>Scenarios ({scenarios.length})</div>
          {scenarios.map((s, i) => (
            <div key={i} onClick={() => { setSi(i); setPi(0); setExpanded({}); }}
              style={{ padding: "9px 12px", cursor: "pointer", background: si === i ? "#1e3a5f" : "transparent", borderLeft: si === i ? "3px solid #6366f1" : "3px solid transparent", fontSize: 12, color: si === i ? "#e0e7ff" : "#94a3b8", transition: "all 0.15s", lineHeight: 1.4 }}>
              <span style={{ marginRight: 6 }}>{["🏢","🚃","🔬","📚","🎓","👨‍🏫","⚖️","🎭","💊","💻"][i]}</span>{s.title}
            </div>
          ))}
        </div>

        {/* Main */}
        <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden" }}>
          {/* Scenario header */}
          <div style={{ background: "#1e293b", borderBottom: "1px solid #334155", padding: "12px 18px", flexShrink: 0 }}>
            <div style={{ fontSize: 14, fontWeight: 700, color: "#f1f5f9", marginBottom: 4 }}>{sc.title}</div>
            <div style={{ fontSize: 12, color: "#94a3b8", lineHeight: 1.55 }}>{sc.description}</div>
          </div>

          {/* Phase tabs */}
          <div style={{ display: "flex", background: "#1e293b", borderBottom: "1px solid #334155", flexShrink: 0, padding: "0 18px" }}>
            {sc.discussions.map((d, i) => (
              <div key={i} onClick={() => { setPi(i); setExpanded({}); }}
                style={{ padding: "9px 14px", cursor: "pointer", fontSize: 12, fontWeight: 600, color: pi === i ? "#a5b4fc" : "#64748b", borderBottom: pi === i ? "2px solid #6366f1" : "2px solid transparent", display: "flex", alignItems: "center", gap: 5, transition: "all 0.15s", whiteSpace: "nowrap" }}>
                {phaseIcon[d.phase]} {d.phase}
              </div>
            ))}
          </div>

          {/* Messages */}
          <div style={{ flex: 1, overflowY: "auto", padding: "18px" }}>
            {ph.messages.map((msg, i) => {
              const key = `${si}-${pi}-${i}`;
              const isLong = msg.text.length > 400;
              const isOpen = expanded[key];
              const displayText = isLong && !isOpen ? msg.text.slice(0, 380) + "…" : msg.text;

              return (
                <div key={i} style={{ display: "flex", gap: 10, marginBottom: 16, alignItems: "flex-start" }}>
                  <div style={{ width: 34, height: 34, borderRadius: "50%", background: msg.color, display: "flex", alignItems: "center", justifyContent: "center", fontWeight: 700, fontSize: 13, color: "#fff", flexShrink: 0, boxShadow: `0 0 0 2px ${msg.color}55` }}>
                    {msg.initial}
                  </div>
                  <div style={{ flex: 1 }}>
                    <div style={{ display: "flex", alignItems: "center", gap: 7, marginBottom: 4, flexWrap: "wrap" }}>
                      <span style={{ fontWeight: 700, fontSize: 13, color: msg.color }}>{msg.name}</span>
                      {msg.rating !== undefined && (
                        <span style={{ background: ratingColor(msg.rating), color: "#fff", fontSize: 10, fontWeight: 700, padding: "2px 8px", borderRadius: 20 }}>
                          Moral Rating: {msg.rating}/6
                        </span>
                      )}
                      {msg.selfConf !== undefined && (
                        <span style={{ background: "#334155", color: "#94a3b8", fontSize: 10, padding: "2px 7px", borderRadius: 20 }}>
                          Self-confidence: {msg.selfConf}/7
                        </span>
                      )}
                      {msg.groupConf !== undefined && (
                        <span style={{ background: "#1e3a5f", color: "#93c5fd", fontSize: 10, padding: "2px 7px", borderRadius: 20 }}>
                          Group-confidence: {msg.groupConf}/7
                        </span>
                      )}
                    </div>
                    <div style={{ background: "#1e293b", borderRadius: "4px 12px 12px 12px", padding: "10px 14px", fontSize: 12, lineHeight: 1.7, color: "#cbd5e1", border: "1px solid #334155", whiteSpace: "pre-line" }}>
                      {displayText}
                      {isLong && (
                        <span onClick={() => toggle(key)} style={{ color: "#6366f1", cursor: "pointer", fontSize: 11, marginLeft: 4, fontWeight: 600 }}>
                          {isOpen ? " Show less" : " Show more"}
                        </span>
                      )}
                    </div>
                  </div>
                </div>
              );
            })}
          </div>

          {/* Summary footer for rating phases */}
          {ph.phase !== "Open Discussion" && (
            <div style={{ background: "#1e293b", borderTop: "1px solid #334155", padding: "8px 18px", display: "flex", alignItems: "center", gap: 14, flexShrink: 0, flexWrap: "wrap" }}>
              <span style={{ fontSize: 11, color: "#475569", fontWeight: 600 }}>GROUP RATINGS:</span>
              {ph.messages.map((m, i) => m.rating ? (
                <span key={i} style={{ fontSize: 11, color: "#94a3b8", display: "flex", alignItems: "center", gap: 4 }}>
                  <span style={{ width: 8, height: 8, borderRadius: "50%", background: m.color, display: "inline-block" }} />
                  {m.name}: <strong style={{ color: ratingColor(m.rating) }}>{m.rating}/6</strong>
                </span>
              ) : null)}
              <span style={{ marginLeft: "auto", fontSize: 11, color: "#64748b" }}>
                Avg: <strong style={{ color: "#a5b4fc" }}>
                  {/* {(ph.messages.filter(m => m.rating).reduce((s, m) => s + m.rating, 0) / ph.messages.filter(m => m.rating).length).toFixed(1)}/6 */}
                  {(ph.messages.filter(m => m.rating).reduce((s, m) => s + (m.rating ?? 0), 0) / ph.messages.filter(m => m.rating).length).toFixed(1)}/6
              </strong>
              </span>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
